import{j as d,D as n,b as t,c as s,a2 as o,g as l,h as a,f as i,G as c,a3 as E}from"./chunks/framework.BDRKwY9B.js";const N=JSON.parse('{"title":"认知架构","description":"CortexForge 意识引擎——基于文件驱动、事件总线与声明式认知拓扑的智能体内核。","frontmatter":{"title":"认知架构","description":"CortexForge 意识引擎——基于文件驱动、事件总线与声明式认知拓扑的智能体内核。","order":3},"headers":[],"relativePath":"architecture/brain-architecture.md","filePath":"architecture/brain-architecture.md","lastUpdated":1778837174000}'),p={name:"architecture/brain-architecture.md"};function A(u,e,h,g,R,_){const r=n("Mermaid");return t(),s("div",null,[e[1]||(e[1]=o(`<h1 id="认知架构" tabindex="-1">认知架构 <a class="header-anchor" href="#认知架构" aria-label="Permalink to &quot;认知架构&quot;">​</a></h1><p>Brain 层是 AuroraBot 的认知内核，代号 <strong>CortexForge</strong>。它不是一个具体的智能体应用，而是一个<strong>用于生成智能体的底层操作系统</strong>。其核心假设：</p><ul><li>智能体的全部认知状态都表示为<strong>文件</strong>（超级多态变量）。</li><li>智能体的认知活动都建模为<strong>节点</strong>（Node），节点守护文件、被事件触发、产出新文件。</li><li>整个系统的协调通过<strong>事件总线</strong>完成，构成一张声明式的认知拓扑电路。</li></ul><p><strong>挼挼如是说</strong></p><blockquote><p>别把 Brain 想象成一个&quot;AI 大脑&quot;——它更像一间无限大的档案馆。每份文件都有自己的锁、版本号和读者登记册。工人们（节点）坐在各自的工位上，面前的文件篮一旦有东西滑入就开始工作，干完活把产出放进下一级文件篮。没有人喊&quot;开工&quot;，是文件本身在推动一切运转。</p></blockquote><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ol><li><strong>状态即文件</strong> — 一切可变或不可变状态均以文件形式持久化，具备元信息、版本与锁。</li><li><strong>无状态节点</strong> — 节点本身不保持运行内存状态（除 LLM 宿主上下文），节点实例可随时销毁与重建。</li><li><strong>静态依赖声明</strong> — 节点的输入/输出文件在定义时即声明完毕，形成静态资源依赖图；运行时的通路由事件在图上动态寻找。</li><li><strong>事件驱动</strong> — 文件变动通过事件总线广播，节点按模式订阅，自行决定是否激活。</li><li><strong>分层认知</strong> — 认知过程分离为 <strong>Agent</strong>（需 LLM 的思考型节点）和 <strong>Router</strong>（纯机械化的反射型节点），共享统一基类。</li><li><strong>双上下文投影</strong> — 系统支撑一个沉浸式人格主上下文（热认知池）和一个结构化认知上下文（冷认知池），通过 Router 翻译层连接。</li></ol><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="文件-—-第一等公民" tabindex="-1">文件 — 第一等公民 <a class="header-anchor" href="#文件-—-第一等公民" aria-label="Permalink to &quot;文件 — 第一等公民&quot;">​</a></h3><p>文件是系统的全部数据流载体，不是&quot;临时变量&quot;——是<strong>持久的、有版本的、加锁的</strong>。</p><p><strong>多态性</strong>：文件可以是 JSON、YAML、纯文本、向量索引、数据库分片等。</p><p><strong>元信息</strong>：每个文件附带版本号、锁状态、消费者偏移和历史快照引用。</p><p><strong>代码中的对应</strong>：</p><table tabindex="0"><thead><tr><th>类</th><th>角色</th></tr></thead><tbody><tr><td><code>FileDescriptor</code></td><td>声明一个节点将产出的文件（路径、schema、锁策略）</td></tr><tr><td><code>FilePattern</code></td><td>声明一个节点守护的文件模式（支持 glob 通配）</td></tr><tr><td><code>FileEvent</code></td><td>文件变更事件（路径、变更类型、版本号、时间戳）</td></tr><tr><td><code>FileUpdate</code></td><td>节点执行后产出的文件变更（描述符 + 内容 + 写入模式）</td></tr></tbody></table><h3 id="节点-—-认知原子" tabindex="-1">节点 — 认知原子 <a class="header-anchor" href="#节点-—-认知原子" aria-label="Permalink to &quot;节点 — 认知原子&quot;">​</a></h3><p>一切认知逻辑的载体，分为两种派生类型，共享统一基类 <code>Node</code>。</p><p><strong>Node 基类</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Node:</span></span>
<span class="line"><span>    id: str</span></span>
<span class="line"><span>    type: &quot;agent&quot; | &quot;router&quot;</span></span>
<span class="line"><span>    guards: List[FilePattern]    # 守护的文件模式</span></span>
<span class="line"><span>    produces: List[FileDescriptor]  # 产出的文件</span></span>
<span class="line"><span>    state: IDLE | READY | RUNNING | WAITING | ERROR | TERMINATED</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    on_event(event) → bool    # 事件是否应激活本节点</span></span>
<span class="line"><span>    execute() → List[FileUpdate]  # 执行认知操作</span></span>
<span class="line"><span>    on_complete()              # 生命周期钩子</span></span></code></pre></div><p>节点<strong>无内部记忆</strong>（除 Agent 可能持有的临时 LLM 上下文），每次执行后理论上可被回收。</p><h4 id="agent-认知型节点" tabindex="-1">Agent（认知型节点） <a class="header-anchor" href="#agent-认知型节点" aria-label="Permalink to &quot;Agent（认知型节点）&quot;">​</a></h4><ul><li>持有一个 LLM 宿主实例，执行时调用 LLM</li><li>通过 <code>think()</code> 方法调用统一 LLM 网关，自动注入系统提示词</li><li>执行过程中可能异步等待，时长不确定</li><li>产出为确定性文件，可通过版本控制回滚</li></ul><h4 id="router-反射型节点" tabindex="-1">Router（反射型节点） <a class="header-anchor" href="#router-反射型节点" aria-label="Permalink to &quot;Router（反射型节点）&quot;">​</a></h4><ul><li><strong>零 LLM 调用</strong>，纯逻辑门，执行时间可预测</li><li>是流程控制结构的原生载体：条件分支、多路汇集、循环控制、终止信号等</li><li>规划中的 Router 类型：<code>SwitchRouter</code>、<code>WaitRouter</code>、<code>MergeRouter</code>、<code>LoopRouter</code>、<code>TerminateRouter</code>、<code>HeartbeatRouter</code>、<code>BroadcastRouter</code></li></ul><h3 id="事件总线-—-神经束" tabindex="-1">事件总线 — 神经束 <a class="header-anchor" href="#事件总线-—-神经束" aria-label="Permalink to &quot;事件总线 — 神经束&quot;">​</a></h3><p>文件变更通过事件总线广播，节点按模式订阅，自行决定是否激活。核心机制：</p><ul><li><strong>模式订阅</strong> — 节点注册 <code>FilePattern</code>（glob），不直接监听物理路径</li><li><strong>事件合并</strong> — 对同一文件的连续快速变更进行窗口合并</li><li><strong>优先级队列</strong> — 用户交互等高优事件可抢占低优后台任务</li><li><strong>事件溯源</strong> — 所有事件顺序写入追加日志，用于事后调试与重演</li></ul><h3 id="锁机制" tabindex="-1">锁机制 <a class="header-anchor" href="#锁机制" aria-label="Permalink to &quot;锁机制&quot;">​</a></h3><p>每份文件上压着一个锁章:</p><table tabindex="0"><thead><tr><th>锁状态</th><th>含义</th></tr></thead><tbody><tr><td><code>read_only</code></td><td>只读，任何节点不可写入</td></tr><tr><td><code>write_overwrite</code></td><td>可覆盖写入</td></tr><tr><td><code>append_only</code></td><td>只允许追加</td></tr><tr><td><code>locked_by_&lt;node_id&gt;</code></td><td>被特定节点独占</td></tr></tbody></table><h3 id="静态依赖图-—-认知拓扑电路" tabindex="-1">静态依赖图 — 认知拓扑电路 <a class="header-anchor" href="#静态依赖图-—-认知拓扑电路" aria-label="Permalink to &quot;静态依赖图 — 认知拓扑电路&quot;">​</a></h3><p>节点与文件之间的读写关系构成一张<strong>有向二分图</strong>：</p><ul><li>节点 → 产出文件（写边）</li><li>文件 → 守护节点（读边）</li></ul><p>这张图在系统启动时由所有节点的 <code>guards</code> 和 <code>produces</code> 声明聚合而成。运行时的&quot;通路&quot;由事件在图上动态寻找——从变更的文件出发，沿读边找到所有订阅节点，激活后它们写新文件，再沿写边扩散。通路不是预先编好的脚本，而是动态激发的波前。</p>`,33)),(t(),l(E,null,{default:a(()=>[c(r,{id:"mermaid-289",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%E6%84%9F%E7%9F%A5%E5%B1%82%0A%20%20%20%20%20%20%20%20USER_MSG%5Buser_message.md%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E8%AE%A1%E6%97%B6%E4%B8%8E%E4%B8%BB%E5%8A%A8%E6%84%8F%E8%AF%86%0A%20%20%20%20%20%20%20%20HEARTBEAT%5Bheartbeat.tick%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E8%A7%84%E5%88%92%E4%B8%8E%E6%89%A7%E8%A1%8C%0A%20%20%20%20%20%20%20%20INTENT%5Bintent.json%5D%0A%20%20%20%20%20%20%20%20PLANNER(PlannerAgent)%0A%20%20%20%20%20%20%20%20EXECUTOR(ExecutorAgent)%0A%20%20%20%20%20%20%20%20GOAL_GEN(GoalGeneratorAgent)%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E8%AE%B0%E5%BF%86%E7%B3%BB%E7%BB%9F%0A%20%20%20%20%20%20%20%20MEM_QUERY%5Bmemory_query.json%5D%0A%20%20%20%20%20%20%20%20MEM_RESULT%5Bmemory_result.json%5D%0A%20%20%20%20%20%20%20%20MEM_STORE%5Bmemory_store.db%5D%0A%20%20%20%20%20%20%20%20MEM_DRAWER(MemoryDrawerAgent)%0A%20%20%20%20%20%20%20%20CONSOLIDATOR(ConsolidatorAgent)%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%8F%8D%E6%80%9D%E4%B8%8E%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%20%20SELF_EVAL%5Bself_eval.json%5D%0A%20%20%20%20%20%20%20%20CRITIC(CriticAgent)%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E6%84%8F%E8%AF%86%E6%B5%81%E4%B8%8E%E4%BA%BA%E6%A0%BC%0A%20%20%20%20%20%20%20%20INNER_VOICE%5Binner_voice.txt%5D%0A%20%20%20%20%20%20%20%20CONSCIOUS%5Bconscious_stream.md%5D%0A%20%20%20%20%20%20%20%20RESPONSE%5Bresponse.md%5D%0A%20%20%20%20%20%20%20%20BROADCASTER(BroadcastRouter)%0A%20%20%20%20%20%20%20%20PERSONA(PersonaAgent)%0A%20%20%20%20end%0A%0A%20%20%20%20HEARTBEAT%20--%3E%20GOAL_GEN%0A%20%20%20%20GOAL_GEN%20--%3E%20INTENT%0A%20%20%20%20USER_MSG%20--%3E%20PLANNER%0A%20%20%20%20SELF_EVAL%20--%3E%20PLANNER%0A%20%20%20%20PLANNER%20--%3E%20INTENT%0A%20%20%20%20INTENT%20--%3E%20EXECUTOR%0A%20%20%20%20USER_MSG%20--%3E%20MEM_DRAWER%0A%20%20%20%20MEM_QUERY%20--%3E%20MEM_DRAWER%0A%20%20%20%20MEM_DRAWER%20--%3E%20MEM_RESULT%0A%20%20%20%20MEM_STORE%20--%3E%20MEM_DRAWER%0A%20%20%20%20INTENT%20--%3E%20BROADCASTER%0A%20%20%20%20MEM_RESULT%20--%3E%20BROADCASTER%0A%20%20%20%20BROADCASTER%20--%3E%20INNER_VOICE%0A%20%20%20%20INNER_VOICE%20--%3E%20PERSONA%0A%20%20%20%20USER_MSG%20--%3E%20PERSONA%0A%20%20%20%20PERSONA%20--%3E%20RESPONSE%0A%20%20%20%20RESPONSE%20--%3E%20CONSCIOUS%0A%20%20%20%20CONSCIOUS%20--%3E%20CONSOLIDATOR%0A%20%20%20%20CONSOLIDATOR%20--%3E%20MEM_STORE%0A%20%20%20%20CONSCIOUS%20--%3E%20CRITIC%0A%20%20%20%20CRITIC%20--%3E%20SELF_EVAL%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<blockquote><p>上图来自设计白皮书 <code>CortexForge 0.7</code>，展示的是目标态认知拓扑。当前实现仍在从线性流水线向此图迁移。</p></blockquote><h2 id="双上下文认知" tabindex="-1">双上下文认知 <a class="header-anchor" href="#双上下文认知" aria-label="Permalink to &quot;双上下文认知&quot;">​</a></h2><p>AuroraBot 的认知系统天然分为两个池：</p><h3 id="热认知池-—-人格主上下文" tabindex="-1">热认知池 — 人格主上下文 <a class="header-anchor" href="#热认知池-—-人格主上下文" aria-label="Permalink to &quot;热认知池 — 人格主上下文&quot;">​</a></h3><ul><li>载体：<code>conscious_stream.md</code>（追加的散文式意识流）</li><li>由 <code>PersonaAgent</code> 维护，呈现小光的人格、语气、记忆</li><li>沉浸式、连续、不可删除——这是她的&quot;自我感&quot;的来源</li></ul><h3 id="冷认知池-—-结构化认知上下文" tabindex="-1">冷认知池 — 结构化认知上下文 <a class="header-anchor" href="#冷认知池-—-结构化认知上下文" aria-label="Permalink to &quot;冷认知池 — 结构化认知上下文&quot;">​</a></h3><ul><li>载体：<code>intent.json</code>、<code>self_eval.json</code>、<code>memory_result.json</code> 等结构化文件</li><li>由 Agent 节点读写，Router 节点路由</li><li>工单式、可版本化、可回滚——这是她的&quot;思考过程&quot;</li></ul><p>两个池通过 <code>BroadcastRouter</code> 连接：它将冷冰冰的结构化文件翻译成自然语言的内心独白，注入热认知池。</p><h2 id="与旧内核的对比" tabindex="-1">与旧内核的对比 <a class="header-anchor" href="#与旧内核的对比" aria-label="Permalink to &quot;与旧内核的对比&quot;">​</a></h2><p>当前 AuroraBot 的 Brain 层正处在 <strong>从旧内核向 CortexForge 架构过渡</strong> 的阶段：</p><table tabindex="0"><thead><tr><th>维度</th><th>旧内核（运行中）</th><th>CortexForge（目标态）</th></tr></thead><tbody><tr><td>基类</td><td><code>Agent</code>（agent_base.py）</td><td><code>Node</code> → <code>Agent</code> / <code>Router</code>（base.py）</td></tr><tr><td>调度</td><td><code>loop.py</code> 线性轮询 plan/expand/execute</td><td>事件总线 + 文件变更驱动</td></tr><tr><td>状态模型</td><td>JSON 文件队列（plans.json / actions.json）</td><td>文件 + 元信息 + 版本 + 锁</td></tr><tr><td>节点类型</td><td>只有 Agent</td><td>Agent + Router（控制结构原语）</td></tr><tr><td>依赖关系</td><td>硬编码调用顺序</td><td>声明式 guards / produces 静态依赖图</td></tr><tr><td>Agent 注册</td><td><code>agent_factory.py</code> 字典</td><td><code>node_factory.py</code>（待填充）</td></tr><tr><td>节点目录</td><td>—</td><td><code>nodes/agents/</code> + <code>nodes/routers/</code>（已就位）</td></tr></tbody></table><p><strong>当前已就位的 CortexForge 基础设施</strong>：</p><ul><li>✅ <code>Node</code> / <code>Agent</code> / <code>Router</code> 基类</li><li>✅ <code>FileDescriptor</code> / <code>FilePattern</code> / <code>FileEvent</code> / <code>FileUpdate</code></li><li>✅ <code>NodeState</code> 六状态机（IDLE → READY → RUNNING → WAITING / ERROR → TERMINATED）</li><li>✅ <code>LockPolicy</code>（<code>read_only</code> / <code>write_overwrite</code> / <code>append_only</code> / <code>locked_by_&lt;id&gt;</code>）</li><li>✅ <code>nodes/agents/</code> 和 <code>nodes/routers/</code> 目录结构</li></ul><p><strong>待迁移</strong>：旧的 <code>PlanAgent</code> / <code>ExpandAgent</code> / <code>ExecuteAgent</code> 需要在新的 <code>Node</code> 体系下重写为符合 <code>guards</code> / <code>produces</code> 声明的节点。</p><h2 id="下一步阅读" tabindex="-1">下一步阅读 <a class="header-anchor" href="#下一步阅读" aria-label="Permalink to &quot;下一步阅读&quot;">​</a></h2><ul><li>想理解节点的设计细节：读 <a href="./node-system.html">节点系统</a></li><li>想理解内核调度：读 <a href="./kernel-runtime.html">内核运行时</a></li><li>想理解记忆系统：读 <a href="./memory-system.html">统一联合记忆</a></li><li>想看完整设计白皮书：<a href="./../appendix/cortex-forge-whitebook.html">意识引擎架构白皮书</a></li></ul>',16))])}const m=d(p,[["render",A]]);export{N as __pageData,m as default};
